function taxonomyTerms(entry) { return [...entry.aliases, ...entry.capabilities].map((term) => String(term).toLowerCase()); }

const taxonomyByService = Object.fromEntries(andwellMasterTaxonomy.map((entry) => [entry.serviceLine, entry]));

const serviceModels = Object.fromEntries(andwellMasterTaxonomy.map((entry) => {
  const hospiceLike = /hospice|palliative|bereavement|comfort|spiritual/i.test(entry.serviceLine);
  const woundLike = /wound/i.test(entry.serviceLine);
  const therapyLike = /therapy|audiology/i.test(entry.serviceLine);
  return [entry.serviceLine, {
    color: hospiceLike ? "#4f3b8f" : woundLike ? "#9f1d1d" : therapyLike ? "#116b5f" : "#2357c6",
    reimbursement: hospiceLike ? 11200 : woundLike ? 1800 : therapyLike ? 1650 : 3189,
    margin: hospiceLike ? 0.16 : woundLike ? 0.24 : therapyLike ? 0.2 : 0.18,
    demandRate: hospiceLike ? 0.012 : woundLike ? 0.025 : therapyLike ? 0.05 : 0.08,
    staffingRatio: hospiceLike ? 18 : woundLike ? 15 : therapyLike ? 20 : 25,
    keywords: taxonomyTerms(entry)
  }];
}));

