  const serviceWeight = inferredServices.length ? inferredServices.reduce((sum, service) => /Home Healthcare|At Home|Care Giving/i.test(service) ? sum + 14 : /Hospice|Palliative/i.test(service) ? sum + 12 : /Wound/i.test(service) ? sum + 10 : /Therapy|Audiology/i.test(service) ? sum + 8 : sum + 6, 0) : 0;
